import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"永佑殿","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/yongyou-dian.md","filePath":"religion/yonghegong/yongyou-dian.md","lastUpdated":1784720050000}'),i={name:"religion/yonghegong/yongyou-dian.md"};function n(r,t,d,s,g,h){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="永佑殿" tabindex="-1">永佑殿 <a class="header-anchor" href="#永佑殿" aria-label="Permalink to &quot;永佑殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1590301729964-23833732ee04?w=1200&amp;q=80" alt="永佑殿红墙殿宇"></p><blockquote><p>&quot;龙寝旧地，梓宫曾停——三尊白檀佛像静默垂目，东西配殿里，藏医与历算的学问仍在流传。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>永佑殿是雍和宫中轴线上的第四进大殿，&quot;永佑&quot;取&quot;永久佑护&quot;之意。这里原是雍亲王府的内寝正殿，即雍亲王胤禛日常起居的寝殿；胤禛即位后，此处成为行宫内殿。雍正十三年（1735年）雍正帝驾崩，梓宫自圆明园移奉雍和宫，即停放于此殿，随后殿宇改覆黄瓦。一座寝殿，由起居而停灵，由停灵而奉佛，身世之跌宕，全寺无出其右。</p><p>改寺后，永佑殿内供奉三尊白檀木雕佛像：中为无量寿佛（阿弥陀佛的报身相），东为药师佛，西为狮吼佛。殿前东西配殿，则分别是藏传佛教四大扎仓中的医药殿与数学殿，是清代藏医学与历算学的研习重镇。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格与内容</th></tr></thead><tbody><tr><td style="text-align:left;">殿宇规制</td><td style="text-align:left;">面阔五间，单檐歇山黄琉璃瓦顶，原王府内寝正殿</td></tr><tr><td style="text-align:left;">正中主供</td><td style="text-align:left;">无量寿佛（白檀木雕），主长寿之法</td></tr><tr><td style="text-align:left;">东侧</td><td style="text-align:left;">药师佛（白檀木雕），主消灾祛病、延寿安康</td></tr><tr><td style="text-align:left;">西侧</td><td style="text-align:left;">狮吼佛（白檀木雕），骑狮作吼，以降伏毒龙、护持正法</td></tr><tr><td style="text-align:left;">东配殿</td><td style="text-align:left;">原医药殿（曼巴扎仓），研习藏医藏药</td></tr><tr><td style="text-align:left;">西配殿</td><td style="text-align:left;">原数学殿（丁科尔扎仓），研习历法、数学与天文</td></tr></tbody></table><p>三尊佛像均以整块白檀木雕成，木质温润，刀法圆熟，历二百余年仍香气隐约。无量寿佛居中，寓意福寿绵长；药师佛手托药钵，疗愈众生身心之疾；狮吼佛则是观音菩萨的忿怒化身，传说以狮子吼声降伏兴风作浪的毒龙，护一方安宁。</p><h3 id="四大扎仓中的两所学府" tabindex="-1">四大扎仓中的两所学府 <a class="header-anchor" href="#四大扎仓中的两所学府" aria-label="Permalink to &quot;四大扎仓中的两所学府&quot;">​</a></h3><p>雍和宫改寺后仿照拉萨三大寺设立扎仓（学院），共四所，分设于中路殿宇及两侧配殿：</p><table tabindex="0"><thead><tr><th style="text-align:left;">扎仓</th><th style="text-align:left;">汉名</th><th style="text-align:left;">研习内容</th></tr></thead><tbody><tr><td style="text-align:left;">参尼扎仓</td><td style="text-align:left;">显宗殿</td><td style="text-align:left;">显宗经论、因明学、佛学哲学</td></tr><tr><td style="text-align:left;">居巴扎仓</td><td style="text-align:left;">密宗殿</td><td style="text-align:left;">密宗仪轨、坛城修持、灌顶传承</td></tr><tr><td style="text-align:left;">曼巴扎仓</td><td style="text-align:left;">医药殿（东配殿）</td><td style="text-align:left;">藏医《四部医典》、药材炮制与诊疗</td></tr><tr><td style="text-align:left;">丁科尔扎仓</td><td style="text-align:left;">数学殿（西配殿）</td><td style="text-align:left;">时轮历算、数学、天文推步</td></tr></tbody></table><p>医药殿所传藏医，以《四部医典》为根本，兼习药浴、针灸与藏药配伍，学僧兼通医理与药理；数学殿所传时轮历法，是蒙藏地区沿用数百年的历法体系，学僧须精通天文测算与数理推演，每年编制颁行历书。清代蒙古、藏地学僧来京，多在此深造考核，学成者返回本寺任教——永佑殿前的两座配殿，曾是名副其实的&quot;皇家佛学院&quot;，也是藏医药与历算学向内地传播的枢纽。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="梓宫停灵与黄瓦之变" tabindex="-1">梓宫停灵与黄瓦之变 <a class="header-anchor" href="#梓宫停灵与黄瓦之变" aria-label="Permalink to &quot;梓宫停灵与黄瓦之变&quot;">​</a></h3><p>雍正十三年（1735年）八月二十三日，雍正帝驾崩。梓宫先奉于乾清宫，随后移至雍和宫，停放于这座昔日的寝殿之中。乾隆帝即位后，为奉父灵，将永佑殿及中路主要殿宇的绿瓦尽改黄瓦。同年十一月，梓宫由此启行，奉安河北易县泰陵。寝殿变灵堂、绿瓦变黄瓦——永佑殿是雍正—乾隆之际那段国丧岁月最直接的见证者。</p><h3 id="寝殿缘何奉-寿" tabindex="-1">寝殿缘何奉&quot;寿&quot; <a class="header-anchor" href="#寝殿缘何奉-寿" aria-label="Permalink to &quot;寝殿缘何奉&quot;寿&quot;&quot;">​</a></h3><p>停灵之地改奉无量寿佛，并非偶然。藏传佛教视生死为轮回，无量寿佛（阿弥陀佛）接引往生、赐予长寿，药师佛疗疾延寿，狮吼佛降魔护法——三尊佛的组合，既是对先帝的追荐超拔，也是对在世者的福寿祝祷。&quot;永佑&quot;之名，恰是这份心意的写照。</p><h3 id="章嘉国师与雍和宫的规制" tabindex="-1">章嘉国师与雍和宫的规制 <a class="header-anchor" href="#章嘉国师与雍和宫的规制" aria-label="Permalink to &quot;章嘉国师与雍和宫的规制&quot;">​</a></h3><p>雍和宫改寺后的殿堂布局、佛像供设与学经制度，多出自三世章嘉呼图克图若必多吉的擘画。章嘉国师是乾隆帝的佛法上师，自幼与弘历（乾隆）同窗共读，一生辅佐清廷处理蒙藏宗教事务。正是在他的主持规划下，雍和宫仿拉萨寺院设立四大扎仓、安设显密诸佛，使一座王府行宫蜕变为制度完备的格鲁派大寺。今日永佑殿的白檀三佛与东西配殿的学经格局，仍可见当年规划之遗意。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>雍正寝殿与停灵处</strong>：王府内寝、帝王梓宫、佛寺正殿三重身份叠加，全寺历史感最浓的一殿。</li><li><strong>三尊白檀木雕佛像</strong>：无量寿佛、药师佛、狮吼佛，均为整木雕刻，近三百年仍保存完好。</li><li><strong>医药殿与数学殿</strong>：东西配殿即藏传佛教四大扎仓中的两所，藏医与历算的传承之地。</li><li><strong>黄瓦规制</strong>：殿顶黄琉璃瓦即雍正停灵时所改，是&quot;因丧升格&quot;的实物印记。</li><li><strong>长寿祈福</strong>：无量寿佛主长寿之法，是许多信众专程叩拜之处。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>三尊白檀佛像木质温润，细观刀工，可辨与铜铸佛像的不同质感。</li><li>东西配殿常设藏医药、历算相关展陈，时间允许可入内浏览。</li><li>为长辈祈福者，可在无量寿佛前随喜供养、默祷安康。</li><li>此殿游客较主殿少，适宜静立片刻，感受寝殿旧地的肃穆氛围。</li><li>殿内禁止拍照，请勿触摸佛像与供器。</li></ul><hr><p><strong>📍 位置</strong>：雍和宫中轴线第四进院落，雍和宫殿以北 <strong>⏱️ 建议游览</strong>：15-20分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/yonghegong/">雍和宫概览</a></p><p><strong>⬅️ 上一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yonghe-dadian.html">雍和宫殿（大雄宝殿）</a> ｜ <strong>➡️ 下一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/falun-dian.html">法轮殿</a></p>',27)])])}const y=e(i,[["render",n]]);export{f as __pageData,y as default};
